def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    N, D = points.shape

    if k <= 0:
        return np.zeros((0, D), dtype=float)

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (D,):
        raise ValueError("reference_point must have shape (D,)")

    # Helper: compute union volume of boxes anchored at ref with upper corners given by boxes (m, D)
    def union_boxes_volume(boxes, ref):
        boxes = np.asarray(boxes, dtype=float)
        if boxes.size == 0:
            return 0.0
        # Keep only boxes with positive volume: all coordinates > ref
        mask_pos = np.all(boxes > ref, axis=1)
        boxes = boxes[mask_pos]
        if boxes.shape[0] == 0:
            return 0.0

        def _union_recursive(bxs, r):
            if bxs.shape[0] == 0:
                return 0.0
            d = r.size
            if d == 1:
                max_end = np.max(bxs[:, 0])
                return max(0.0, max_end - r[0])
            # unique sorted coordinates along first dimension including ref
            coords = np.unique(np.concatenate(([r[0]], bxs[:, 0])))
            coords.sort()
            total = 0.0
            # sweep intervals [coords[i], coords[i+1]]
            for i in range(len(coords) - 1):
                x_left = coords[i]
                x_right = coords[i + 1]
                if x_right <= x_left:
                    continue
                # boxes that reach at least x_right
                mask = bxs[:, 0] >= x_right
                if not np.any(mask):
                    continue
                sub_boxes = bxs[mask][:, 1:]
                sub_ref = r[1:]
                sub_vol = _union_recursive(sub_boxes, sub_ref)
                if sub_vol > 0.0:
                    total += (x_right - x_left) * sub_vol
            return total

        return float(_union_recursive(boxes, ref))

    # Quick singleton volumes
    single_volumes = np.zeros(N, dtype=float)
    for i in range(N):
        single_volumes[i] = union_boxes_volume(points[i:i+1, :], reference_point)

    if k >= N:
        return points.copy()

    selected_indices = []
    remaining = set(range(N))

    # Pre-sort candidates by singleton volumes descending for screening
    idx_sorted_by_single = np.argsort(-single_volumes)

    current_volume = 0.0
    selected_boxes = np.zeros((0, D), dtype=float)

    # Beam size: adaptively choose a screening size to reduce evaluations
    # Keep at least 1 and at most min(200, N)
    max_beam = min(200, N)

    for t in range(min(k, N)):
        if len(remaining) == 0:
            break
        # construct list of remaining indices sorted by singleton volume (descending)
        rem_list_sorted = [idx for idx in idx_sorted_by_single if idx in remaining]
        # choose beam candidates (top by singleton volume). This speeds up search while keeping good options.
        beam_size = min(max_beam, max(1, int(max(5, len(rem_list_sorted) * 0.2))))
        candidates = rem_list_sorted[:beam_size]

        best_idx = None
        best_gain = -1.0

        # Evaluate only beam candidates (fast screening)
        for idx in candidates:
            if single_volumes[idx] <= 0.0 and current_volume > 0:
                candidate_gain = 0.0
            else:
                if selected_boxes.shape[0] == 0:
                    vol_with = single_volumes[idx]
                else:
                    combined = np.vstack((selected_boxes, points[idx:idx+1, :]))
                    vol_with = union_boxes_volume(combined, reference_point)
                candidate_gain = vol_with - current_volume
            if candidate_gain > best_gain + 1e-12:
                best_gain = candidate_gain
                best_idx = idx

        # If top-beam candidate gave no improvement, try a final pass over all remaining to catch stray better ones
        if best_gain <= 1e-12:
            for idx in remaining:
                if idx in candidates:
                    continue
                if single_volumes[idx] <= 0.0 and current_volume > 0:
                    candidate_gain = 0.0
                else:
                    if selected_boxes.shape[0] == 0:
                        vol_with = single_volumes[idx]
                    else:
                        combined = np.vstack((selected_boxes, points[idx:idx+1, :]))
                        vol_with = union_boxes_volume(combined, reference_point)
                    candidate_gain = vol_with - current_volume
                if candidate_gain > best_gain + 1e-12:
                    best_gain = candidate_gain
                    best_idx = idx

        if best_idx is None:
            break

        # Add best
        selected_indices.append(best_idx)
        remaining.remove(best_idx)
        if selected_boxes.shape[0] == 0:
            selected_boxes = points[best_idx:best_idx+1, :].copy()
        else:
            selected_boxes = np.vstack((selected_boxes, points[best_idx:best_idx+1, :]))
        current_volume = union_boxes_volume(selected_boxes, reference_point)

        # Early stop if no gain possible
        if best_gain <= 1e-12:
            break

    # If we didn't select enough (due to zero gains), append highest-singleton remaining
    if len(selected_indices) < k:
        rem_sorted = [idx for idx in idx_sorted_by_single if idx in remaining]
        need = k - len(selected_indices)
        take = rem_sorted[:need]
        for idx in take:
            selected_indices.append(idx)
            if idx in remaining:
                remaining.remove(idx)
        if selected_boxes.shape[0] == 0 and len(selected_indices) > 0:
            selected_boxes = points[np.array(selected_indices, dtype=int), :]
        else:
            if len(take) > 0:
                selected_boxes = np.vstack((selected_boxes, points[np.array(take, dtype=int), :]))
        current_volume = union_boxes_volume(selected_boxes, reference_point)

    # Local 1-for-1 swap improvement (limited iterations)
    max_swap_iters = 5
    swap_iter = 0
    selected_set = set(selected_indices)
    remaining_list = list(remaining)
    while swap_iter < max_swap_iters:
        improved = False
        # Try swaps: for each selected index, try replacing with top candidates by singleton volume from remaining
        rem_sorted = [idx for idx in idx_sorted_by_single if idx in remaining]
        # limit candidates considered per selected to speed up
        cand_limit = min(100, max(10, len(rem_sorted)))
        top_cands = rem_sorted[:cand_limit]
        for s_pos, s_idx in enumerate(list(selected_indices)):
            # build boxes without s_idx
            others = [idx for idx in selected_indices if idx != s_idx]
            if len(others) == 0:
                base_boxes = np.zeros((0, D), dtype=float)
            else:
                base_boxes = points[np.array(others, dtype=int), :]
            base_vol = union_boxes_volume(base_boxes, reference_point)
            best_local_gain = 0.0
            best_local_idx = None
            for c_idx in top_cands:
                if c_idx == s_idx:
                    continue
                # quick upper bound: singleton volume of candidate
                if single_volumes[c_idx] <= 0.0 and base_vol > 0:
                    candidate_gain = 0.0
                else:
                    if base_boxes.shape[0] == 0:
                        vol_with = single_volumes[c_idx]
                    else:
                        combined = np.vstack((base_boxes, points[c_idx:c_idx+1, :]))
                        vol_with = union_boxes_volume(combined, reference_point)
                    candidate_gain = vol_with - base_vol
                if candidate_gain > best_local_gain + 1e-12:
                    best_local_gain = candidate_gain
                    best_local_idx = c_idx
            # if we found an improving swap (local gain > current contribution of s_idx), perform it
            # compute current contribution of s_idx to full set
            if best_local_idx is not None:
                # current full set volume is current_volume; replacing s_idx with best_local_idx yields base_vol + best_local_gain
                new_total_vol = base_vol + best_local_gain
                if new_total_vol > current_volume + 1e-12:
                    # perform swap
                    selected_indices[s_pos] = best_local_idx
                    selected_set.remove(s_idx)
                    selected_set.add(best_local_idx)
                    remaining.add(s_idx)
                    if best_local_idx in remaining:
                        remaining.remove(best_local_idx)
                    # rebuild selected_boxes and current_volume
                    selected_boxes = points[np.array(selected_indices, dtype=int), :]
                    current_volume = union_boxes_volume(selected_boxes, reference_point)
                    improved = True
                    break  # restart swaps after a successful swap
        if not improved:
            break
        swap_iter += 1

    # Finalize selected array with correct shape
    selected = points[np.array(selected_indices, dtype=int), :]
    # Ensure shape exactly (k, D)
    if selected.shape[0] > k:
        selected = selected[:k, :]
    elif selected.shape[0] < k:
        # pad with best remaining or reference if none
        need = k - selected.shape[0]
        if len(remaining) > 0:
            rem_sorted = [idx for idx in idx_sorted_by_single if idx in remaining]
            take = rem_sorted[:need]
            if selected.shape[0] == 0:
                selected = points[np.array(take, dtype=int), :]
            else:
                selected = np.vstack((selected, points[np.array(take, dtype=int), :]))
            if selected.shape[0] < k:
                extra = k - selected.shape[0]
                pad = np.repeat(selected[-1:, :], extra, axis=0)
                selected = np.vstack((selected, pad))
        else:
            if selected.shape[0] == 0:
                pad = np.tile(reference_point.reshape(1, -1), (k, 1))
                return pad
            extra = need
            pad = np.repeat(selected[-1:, :], extra, axis=0)
            selected = np.vstack((selected, pad))

    return selected

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import pygmo as pg

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    # trivial cases
    if k <= 0:
        return np.zeros((0, d))
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # Helper: determine Pareto-nondominated indices (assuming smaller is better for HV)
    def nondominated_indices(X):
        N = X.shape[0]
        is_nd = np.ones(N, dtype=bool)
        for i in range(N):
            if not is_nd[i]:
                continue
            # compare i to others
            xi = X[i]
            for j in range(N):
                if i == j or not is_nd[j]:
                    continue
                xj = X[j]
                # if xj dominates xi (all <= and any <), mark xi dominated
                if np.all(xj <= xi) and np.any(xj < xi):
                    is_nd[i] = False
                    break
                # if xi dominates xj, mark xj dominated
                if np.all(xi <= xj) and np.any(xi < xj):
                    is_nd[j] = False
        return np.where(is_nd)[0]

    # Precompute single-point hypervolumes (useful for tie-breaking)
    single_hvs = np.zeros(n, dtype=float)
    for i in range(n):
        try:
            single_hvs[i] = float(pg.hypervolume(points[[i], :]).compute(reference_point))
        except Exception:
            single_hvs[i] = 0.0

    # Start by working on the nondominated subset (skyline) to reduce candidates
    candidates_idx = nondominated_indices(points)

    # If skyline is empty (degenerate), fallback to all indices
    if candidates_idx.size == 0:
        candidates_idx = np.arange(n)

    selected_indices = []
    selected_set = set()
    current_hv = 0.0

    # Function to compute hv for a list of indices
    def hv_for_idx_list(idx_list):
        if len(idx_list) == 0:
            return 0.0
        try:
            arr = points[np.array(idx_list, dtype=int)]
            return float(pg.hypervolume(arr).compute(reference_point))
        except Exception:
            return 0.0

    # Greedy selection loop: pick point with largest marginal HV
    for _ in range(k):
        best_cand = None
        best_gain = -np.inf
        # If candidate pool empty, refill from remaining indices
        pool = [int(i) for i in candidates_idx if int(i) not in selected_set]
        if len(pool) == 0:
            pool = [i for i in range(n) if i not in selected_set]
        # compute marginal gains
        for cand in pool:
            # quick pruning: if single_hvs[cand] is zero and many selected, skip as likely zero gain
            # (still compute to be safe)
            new_sel = selected_indices + [int(cand)]
            hv_new = hv_for_idx_list(new_sel)
            gain = hv_new - current_hv
            if gain > best_gain + 1e-15:
                best_gain = gain
                best_cand = int(cand)
            elif abs(gain - best_gain) <= 1e-15 and best_cand is not None:
                # tie-break: prefer larger single_hv, then larger distance to currently selected (diversity)
                if single_hvs[cand] > single_hvs[best_cand] + 1e-15:
                    best_cand = int(cand)
                elif abs(single_hvs[cand] - single_hvs[best_cand]) <= 1e-15:
                    if len(selected_indices) > 0:
                        cur_sel_arr = points[np.array(selected_indices)]
                        cand_dist = np.min(np.linalg.norm(cur_sel_arr - points[cand], axis=1))
                        best_dist = np.min(np.linalg.norm(cur_sel_arr - points[best_cand], axis=1))
                        if cand_dist > best_dist:
                            best_cand = int(cand)
                    else:
                        # if none selected, tie-break by single_hv already handled; else random
                        pass
        # If no positive gain found, still pick the remaining candidate with highest single_hv to fill slots
        if best_cand is None or (best_gain <= 0 and len(selected_indices) + 1 <= k):
            remaining = [i for i in range(n) if i not in selected_set]
            if len(remaining) == 0:
                break
            # pick highest single_hv among remaining
            best_cand = int(max(remaining, key=lambda x: single_hvs[x]))
            # compute its gain for correctness
            hv_new = hv_for_idx_list(selected_indices + [best_cand])
            best_gain = hv_new - current_hv

        # Add chosen
        selected_indices.append(int(best_cand))
        selected_set.add(int(best_cand))
        current_hv += max(0.0, best_gain)

        # Prune candidates: remove points dominated by the new selection (they cannot increase HV)
        # A point p is dominated by chosen if chosen <= p in all dims (assuming smaller is better)
        chosen_point = points[best_cand]
        new_candidates = []
        for idx in candidates_idx:
            if int(idx) in selected_set:
                continue
            pt = points[int(idx)]
            if np.all(chosen_point <= pt) and np.any(chosen_point < pt):
                # dominated by chosen; skip
                continue
            new_candidates.append(int(idx))
        if len(new_candidates) == 0:
            # recompute skyline from remaining unselected points
            remaining_pts_idx = np.array([i for i in range(n) if i not in selected_set], dtype=int)
            if remaining_pts_idx.size == 0:
                candidates_idx = np.array([], dtype=int)
            else:
                candidates_idx = nondominated_indices(points[remaining_pts_idx])
                # map back to original indices
                if candidates_idx.size > 0:
                    candidates_idx = remaining_pts_idx[candidates_idx]
                else:
                    candidates_idx = remaining_pts_idx
        else:
            candidates_idx = np.array(new_candidates, dtype=int)

    # If for some reason we selected fewer than k (e.g., all others dominated), fill with best remaining by single_hv
    if len(selected_indices) < k:
        remaining = [i for i in range(n) if i not in selected_set]
        remaining_sorted = sorted(remaining, key=lambda x: single_hvs[x], reverse=True)
        for idx in remaining_sorted:
            if len(selected_indices) >= k:
                break
            selected_indices.append(int(idx))
            selected_set.add(int(idx))

    selected_indices = selected_indices[:k]
    subset = points[np.array(selected_indices, dtype=int), :]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq
    try:
        import pygmo as pg
    except Exception:
        pg = None

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    # trivial cases
    if k <= 0:
        return np.zeros((0, d), dtype=float)
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # hypervolume computation helper (safe fallback if pygmo not available)
    def hv_of_indices(idx_list):
        if len(idx_list) == 0:
            return 0.0
        arr = points[np.array(idx_list, dtype=int)]
        if pg is None:
            # crude fallback: approximate individual hypervolume as product of (ref - pt) and ignore overlaps
            # this is only used if pygmo is not available
            diffs = np.maximum(reference_point - arr, 0.0)
            try:
                # exact for single point; for multiple points fall back to greedy inclusion-exclusion approx (very rough)
                if arr.shape[0] == 1:
                    return float(np.prod(diffs[0]))
                # approximate union by summing singles and subtracting pairwise overlaps (cheap approx)
                single = np.prod(diffs, axis=1)
                approx = float(single.sum())
                # subtract pairwise min volumes (very cheap approx)
                if arr.shape[0] > 1:
                    for i in range(arr.shape[0]):
                        for j in range(i + 1, arr.shape[0]):
                            mins = np.minimum(diffs[i], diffs[j])
                            approx -= float(np.prod(mins)) * 0.5
                return max(0.0, approx)
            except Exception:
                return 0.0
        else:
            try:
                return float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                return 0.0

    # precompute single-point hypervolumes (used as upper bounds in lazy greedy)
    single_hvs = np.zeros(n, dtype=float)
    for i in range(n):
        single_hvs[i] = hv_of_indices([i])

    # Lazy greedy selection using single_hvs as initial upper bounds.
    # Use a max-heap (implemented via heapq of negatives).
    heap = [(-single_hvs[i], i) for i in range(n)]
    heapq.heapify(heap)

    selected_indices = []
    selected_set = set()
    current_hv = 0.0
    tol = 1e-12
    # Precompute pairwise distances for tie-breaking when needed
    # Only compute if space/time allows: n x n distance could be large, but we compute a compact matrix if n not huge.
    compute_distances = (n <= 2000)  # heuristic threshold
    if compute_distances:
        # squared Euclidean distances
        diff = points[:, None, :] - points[None, :, :]
        dists = np.sqrt(np.maximum((diff ** 2).sum(axis=2), 0.0))
    else:
        dists = None

    # Helper: min distance from a candidate to currently selected set (for tie-break)
    def min_dist_to_selected(idx):
        if len(selected_indices) == 0:
            return np.inf
        if compute_distances:
            return float(np.min(dists[idx, list(selected_set)]))
        else:
            # compute on the fly
            cand = points[idx]
            sel_pts = points[list(selected_set)]
            return float(np.min(np.linalg.norm(sel_pts - cand, axis=1)))

    # Main loop
    while len(selected_indices) < k and heap:
        # Pop candidate with highest upper bound
        ub_neg, idx = heapq.heappop(heap)
        ub = -ub_neg
        if idx in selected_set:
            continue
        # Recompute exact marginal gain
        delta = hv_of_indices(selected_indices + [idx]) - current_hv
        if delta < 0:
            delta = 0.0  # numerical safety
        # Peek at next best upper bound
        if heap:
            next_ub = -heap[0][0]
        else:
            next_ub = -np.inf
        # Acceptance condition: if this candidate's true marginal is >= next's upper bound (lazy greedy)
        if delta + tol >= next_ub:
            # If marginal is essentially zero and we still need points, prefer candidates with larger single_hv or diversity
            if delta <= tol:
                # choose between this candidate and the top few remaining to pick one with better diversity/single_hv
                # gather a small pool
                pool = [idx]
                # peek up to 5 more from heap
                temp = []
                for _ in range(min(5, len(heap))):
                    item = heapq.heappop(heap)
                    temp.append(item)
                    pool.append(item[1])
                # restore heap
                for item in temp:
                    heapq.heappush(heap, item)
                # evaluate diversity score = (single_hv, min_dist_to_selected)
                best = idx
                best_score = (single_hvs[idx], min_dist_to_selected(idx))
                for pid in pool:
                    sc = (single_hvs[pid], min_dist_to_selected(pid))
                    if sc > best_score:
                        best = pid
                        best_score = sc
                # if best is not the popped idx, push the popped idx back with updated bound (its delta=0)
                if best != idx:
                    # push popped one back (with its delta as new bound)
                    heapq.heappush(heap, (-delta, idx))
                    # remove best from heap (find and remove one occurrence)
                    # simple approach: lazily mark by adding a new entry for best with its single_hv and rely on duplicates
                    # add best with its single_hv if not already selected
                    if best not in selected_set:
                        heapq.heappush(heap, (-single_hvs[best], best))
                    continue
                # else accept best which is idx
            # Accept candidate
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
            # Update current_hv exactly
            current_hv = hv_of_indices(selected_indices)
        else:
            # update bound for this candidate and push back
            heapq.heappush(heap, (-delta, idx))

    # If not enough selected (e.g., heap exhausted or all remaining have zero marginal), fill with highest single_hv unselected
    if len(selected_indices) < k:
        remaining = [i for i in range(n) if i not in selected_set]
        remaining_sorted = sorted(remaining, key=lambda x: single_hvs[x], reverse=True)
        for idx in remaining_sorted:
            if len(selected_indices) >= k:
                break
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
        current_hv = hv_of_indices(selected_indices)

    subset = points[np.array(selected_indices, dtype=int), :]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import pygmo as pg
    import heapq
    import random
    from math import isfinite

    rng = random.Random(0)

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D).")
    n, d = points.shape
    if not (isinstance(k, int) and k >= 0):
        raise ValueError("k must be a non-negative integer")
    if k == 0:
        return np.zeros((0, d))
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    def hv_of_array(arr):
        if arr is None or len(arr) == 0:
            return 0.0
        try:
            return float(pg.hypervolume(np.asarray(arr, dtype=float)).compute(reference_point))
        except Exception:
            return 0.0

    def hv_of_indices(indices):
        if len(indices) == 0:
            return 0.0
        arr = points[np.array(indices, dtype=int)]
        return hv_of_array(arr)

    # Compute individual hypervolumes (initial marginal gains w.r.t empty set)
    individual_hv = np.zeros(n, dtype=float)
    for i in range(n):
        try:
            individual_hv[i] = float(pg.hypervolume(points[[i]]).compute(reference_point))
        except Exception:
            individual_hv[i] = 0.0

    # Build max-heap using negative gains; CELF-like lazy greedy:
    # each heap entry: (-gain, idx, last_updated_round)
    # last_updated_round == r means the gain was computed w.r.t. the selected set at round r.
    heap = []
    for i in range(n):
        # add tiny random jitter to break ties randomly but deterministically by seed
        jitter = rng.random() * 1e-12
        heap.append((-(individual_hv[i] + jitter), int(i), 0))
    heapq.heapify(heap)

    selected = []
    selected_set = set()
    current_hv = 0.0

    current_round = 1
    # CELF main loop: need to select k items
    while len(selected) < k and heap:
        neg_gain, idx, last_round = heapq.heappop(heap)
        if idx in selected_set:
            continue  # skip already selected
        gain = -neg_gain
        # If this entry was evaluated for the current selected set (last_round == current_round-1), accept it
        if last_round == current_round - 1:
            # Accept this candidate
            selected.append(int(idx))
            selected_set.add(int(idx))
            # Update current hypervolume
            current_hv = hv_of_indices(selected)
            current_round += 1
            continue
        else:
            # Recompute true marginal gain w.r.t current selected set
            try:
                new_hv = hv_of_indices(selected + [int(idx)])
                new_gain = new_hv - current_hv
            except Exception:
                new_gain = 0.0
            if not isfinite(new_gain):
                new_gain = -np.inf
            if new_gain < 0 and new_gain > -1e-12:
                new_gain = 0.0
            # push updated value with last_round = current_round-1
            jitter = rng.random() * 1e-15
            heapq.heappush(heap, (-(new_gain + jitter), int(idx), current_round - 1))

    # If heap exhausted but still not enough, fill by top individual hv among unselected
    if len(selected) < k:
        remaining_by_ind = [int(i) for i in np.argsort(individual_hv)[::-1] if int(i) not in selected_set]
        for idx in remaining_by_ind:
            if len(selected) >= k:
                break
            selected.append(int(idx))
            selected_set.add(int(idx))
        current_hv = hv_of_indices(selected)

    # Ensure exactly k (truncate if somehow more)
    if len(selected) > k:
        selected = selected[:k]

    subset = points[np.array(selected, dtype=int)]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import heapq
    try:
        import pygmo as pg
    except Exception:
        pg = None

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    if k <= 0:
        return np.zeros((0, d), dtype=float)
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # hypervolume computation helper
    def hv_of_indices(idx_list):
        if len(idx_list) == 0:
            return 0.0
        arr = points[np.array(idx_list, dtype=int)]
        if pg is None:
            # fallback approximate (same as original fallback)
            diffs = np.maximum(reference_point - arr, 0.0)
            try:
                if arr.shape[0] == 1:
                    return float(np.prod(diffs[0]))
                single = np.prod(diffs, axis=1)
                approx = float(single.sum())
                if arr.shape[0] > 1:
                    for i in range(arr.shape[0]):
                        for j in range(i + 1, arr.shape[0]):
                            mins = np.minimum(diffs[i], diffs[j])
                            approx -= float(np.prod(mins)) * 0.5
                return max(0.0, approx)
            except Exception:
                return 0.0
        else:
            try:
                return float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                return 0.0

    # Precompute single-point hypervolumes (upper bounds)
    single_hvs = np.zeros(n, dtype=float)
    for i in range(n):
        single_hvs[i] = hv_of_indices([i])

    # Precompute distances if feasible for diversity measures
    compute_distances = (n <= 2000)
    if compute_distances:
        diff = points[:, None, :] - points[None, :, :]
        dists = np.sqrt(np.maximum((diff ** 2).sum(axis=2), 0.0))
        # average distance to others
        avg_dists = np.maximum(np.mean(dists, axis=1), 0.0)
        max_dist = float(np.max(avg_dists)) if n > 0 else 1.0
    else:
        dists = None
        # approximate avg_dists by sampling up to 500 points to estimate scale
        sample_m = min(500, n)
        rng = np.random.default_rng(0)
        sample_idx = rng.choice(n, sample_m, replace=False)
        avg_dists = np.zeros(n, dtype=float)
        for i in range(n):
            pts = points[sample_idx]
            avg_dists[i] = float(np.mean(np.linalg.norm(pts - points[i], axis=1)))
        max_dist = float(np.max(avg_dists)) if n > 0 else 1.0

    # normalize average distances to [0,1]
    eps = 1e-12
    avg_dists_norm = avg_dists / (max_dist + eps)

    # parameters controlling trade-off (new parameter settings)
    alpha = 0.5  # weight for static diversity (average distance) in initial upper bound
    gamma = 0.5  # weight for dynamic diversity (min distance to already selected) when computing effective marginal

    # initial upper bound score: single_hv augmented by avg-distance diversity
    initial_ub = single_hvs * (1.0 + alpha * avg_dists_norm)

    # heap: max-heap via negatives
    heap = [(-initial_ub[i], i) for i in range(n)]
    heapq.heapify(heap)

    selected_indices = []
    selected_set = set()
    current_hv = 0.0
    tol = 1e-12

    # Helper: min distance from a candidate to currently selected set (for dynamic diversity)
    def min_dist_to_selected(idx):
        if len(selected_indices) == 0:
            return np.inf
        if compute_distances:
            return float(np.min(dists[idx, list(selected_set)]))
        else:
            cand = points[idx]
            sel_pts = points[list(selected_set)]
            return float(np.min(np.linalg.norm(sel_pts - cand, axis=1)))

    # Main lazy-greedy loop with diversity-augmented acceptance criterion
    while len(selected_indices) < k and heap:
        ub_neg, idx = heapq.heappop(heap)
        ub = -ub_neg
        if idx in selected_set:
            continue

        # exact marginal hypervolume gain
        delta = hv_of_indices(selected_indices + [idx]) - current_hv
        if delta < 0:
            delta = 0.0

        # dynamic diversity factor based on min distance to selected set (normalized)
        if len(selected_indices) == 0:
            min_dist_norm = 1.0
        else:
            md = min_dist_to_selected(idx)
            # clamp and normalize by max_dist
            if np.isfinite(md):
                min_dist_norm = float(md) / (max_dist + eps)
                min_dist_norm = min(1.0, max(0.0, min_dist_norm))
            else:
                min_dist_norm = 0.0

        # effective marginal adjusted by diversity (encourages diverse picks)
        effective_delta = delta * (1.0 + gamma * min_dist_norm)

        # peek next best upper bound
        if heap:
            next_ub = -heap[0][0]
        else:
            next_ub = -np.inf

        # Acceptance condition: effective marginal beats next upper bound (heuristic)
        if effective_delta + tol >= next_ub:
            # If marginal essentially zero, prefer more diverse / larger single_hv
            if delta <= tol:
                # consider a small pool to pick the best by combined static+dynamic score
                pool = [idx]
                temp = []
                for _ in range(min(5, len(heap))):
                    item = heapq.heappop(heap)
                    temp.append(item)
                    pool.append(item[1])
                for item in temp:
                    heapq.heappush(heap, item)

                best = idx
                best_score = (single_hvs[idx] * (1.0 + alpha * avg_dists_norm[idx]),
                              min_dist_to_selected(idx) if len(selected_indices) > 0 else np.inf)
                for pid in pool:
                    sc = (single_hvs[pid] * (1.0 + alpha * avg_dists_norm[pid]),
                          min_dist_to_selected(pid) if len(selected_indices) > 0 else np.inf)
                    if sc > best_score:
                        best = pid
                        best_score = sc
                if best != idx:
                    # push back current with its (zero) marginal as a conservative bound
                    heapq.heappush(heap, (-initial_ub[idx], idx))
                    # push best candidate with its initial ub to be considered
                    if best not in selected_set:
                        heapq.heappush(heap, (-initial_ub[best], best))
                    continue

            # accept candidate
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
            current_hv = hv_of_indices(selected_indices)
        else:
            # not accepted: update bound conservatively (keep initial ub which is cheap)
            # push back using the initial augmented ub to retain diversity bias
            heapq.heappush(heap, (-initial_ub[idx], idx))

    # If not enough selected, fill by highest initial_ub among remaining
    if len(selected_indices) < k:
        remaining = [i for i in range(n) if i not in selected_set]
        remaining_sorted = sorted(remaining, key=lambda x: initial_ub[x], reverse=True)
        for idx in remaining_sorted:
            if len(selected_indices) >= k:
                break
            selected_indices.append(int(idx))
            selected_set.add(int(idx))
        current_hv = hv_of_indices(selected_indices)

    subset = points[np.array(selected_indices, dtype=int), :]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    try:
        import pygmo as pg
    except Exception as e:
        raise ImportError("pygmo is required for hypervolume computations (pip install pygmo).") from e

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    if k <= 0:
        return np.zeros((0, d))
    if n == 0:
        return np.zeros((k, d))
    if k >= n:
        return points.copy()

    # Reference point handling
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")
    max_pts = np.max(points, axis=0)
    # Ensure reference_point dominates all points (for maximization objectives)
    eps = 1e-8
    reference_point = np.maximum(reference_point, max_pts + eps)

    # Dominance pruning: keep only non-dominated points (maximization)
    pts = points.copy()
    n2 = pts.shape[0]
    dominated = np.zeros(n2, dtype=bool)
    for i in range(n2):
        if dominated[i]:
            continue
        # j dominates i if j >= i in all dims and j > i in at least one dim
        ge = np.all(pts >= pts[i], axis=1)
        gt = np.any(pts > pts[i], axis=1)
        dom_by = np.where(ge & gt)[0]
        # if any other point dominates i, mark i dominated
        for j in dom_by:
            if j != i:
                dominated[i] = True
                break
    keep_idx = np.where(~dominated)[0]
    if keep_idx.size == 0:
        # fallback: return first k original points
        return points[:min(k, n), :].copy()

    points_f = pts[keep_idx, :]
    orig_idx_map = keep_idx.copy()
    n_f = points_f.shape[0]
    if k >= n_f:
        # if after pruning we have <= k, return all filtered points (pad if necessary)
        subset = points_f.copy()
        if subset.shape[0] < k:
            # pad with best remaining original points if any
            rem_orig = np.setdiff1d(np.arange(n), orig_idx_map, assume_unique=True)
            if rem_orig.size > 0:
                to_add = points[rem_orig[:(k - subset.shape[0])], :]
                subset = np.vstack([subset, to_add])
            else:
                while subset.shape[0] < k:
                    subset = np.vstack([subset, subset[0:1, :]])
        return subset[:k, :].copy()

    # Precompute single-point hypervolumes as quick estimates
    single_hvs = np.empty(n_f, dtype=float)
    for i in range(n_f):
        try:
            single_hvs[i] = pg.hypervolume(points_f[i:i+1, :]).compute(reference_point)
        except Exception:
            single_hvs[i] = 0.0

    # Multi-start greedy:
    # parameters to trade off time vs quality
    restarts = min(8, max(1, n_f // 10))  # number of greedy runs
    seeds_top = min(20, n_f)  # choose seeds from top single_hvs
    top_seed_indices = np.argsort(-single_hvs)[:seeds_top]

    best_subset = None
    best_hv = -np.inf

    for r in range(restarts):
        # choose seed: first run deterministic best, others random from top_seed_indices
        if r == 0:
            seed_idx = int(top_seed_indices[0])
        else:
            # random selection among top seeds to diversify
            seed_idx = int(np.random.choice(top_seed_indices, size=1)[0])

        selected_mask = np.zeros(n_f, dtype=bool)
        selected_list = []
        # start with seed
        selected_list.append(seed_idx)
        selected_mask[seed_idx] = True
        selected_points = points_f[np.array(selected_list), :].copy()
        try:
            hv_current = pg.hypervolume(selected_points).compute(reference_point)
        except Exception:
            hv_current = 0.0

        # greedy add
        for _ in range(1, k):
            best_gain = -np.inf
            best_cand = -1
            # compute actual marginal gain for each remaining candidate
            rem_idx = np.where(~selected_mask)[0]
            if rem_idx.size == 0:
                break
            for c in rem_idx:
                cand = points_f[c:c+1, :]
                try:
                    hv_trial = pg.hypervolume(np.vstack([selected_points, cand])).compute(reference_point)
                except Exception:
                    hv_trial = hv_current
                gain = hv_trial - hv_current
                if gain > best_gain:
                    best_gain = gain
                    best_cand = int(c)
            if best_cand == -1 or best_gain <= 0:
                # no positive gain candidate; fill remaining by top single_hvs (non-selected)
                remaining = np.where(~selected_mask)[0]
                order = remaining[np.argsort(-single_hvs[remaining])]
                for c in order:
                    if len(selected_list) >= k:
                        break
                    selected_list.append(int(c))
                    selected_mask[c] = True
                    selected_points = np.vstack([selected_points, points_f[c:c+1, :]])
                try:
                    hv_current = pg.hypervolume(selected_points).compute(reference_point)
                except Exception:
                    pass
                break
            # accept best_cand
            selected_list.append(best_cand)
            selected_mask[best_cand] = True
            selected_points = np.vstack([selected_points, points_f[best_cand:best_cand+1, :]])
            hv_current = hv_current + max(0.0, best_gain)

        # if fewer than k selected due to some reason, pad by remaining best single_hvs
        if len(selected_list) < k:
            remaining = np.where(~selected_mask)[0]
            if remaining.size > 0:
                order = remaining[np.argsort(-single_hvs[remaining])]
                for c in order:
                    if len(selected_list) >= k:
                        break
                    selected_list.append(int(c))
                    selected_mask[c] = True
                    selected_points = np.vstack([selected_points, points_f[c:c+1, :]])
                try:
                    hv_current = pg.hypervolume(selected_points).compute(reference_point)
                except Exception:
                    pass

        # finalize this run
        # ensure exactly k rows
        if selected_points.shape[0] > k:
            selected_points = selected_points[:k, :]
            selected_list = selected_list[:k]
            try:
                hv_current = pg.hypervolume(selected_points).compute(reference_point)
            except Exception:
                pass

        if hv_current > best_hv:
            best_hv = hv_current
            best_subset = (np.array(selected_list, dtype=int).copy(), selected_points.copy())

    if best_subset is None:
        # fallback: choose top-k by single_hvs
        order = np.argsort(-single_hvs)[:k]
        subset = points_f[order, :].copy()
        # map back
        orig_idx = orig_idx_map[order]
        subset = points[orig_idx, :].copy()
        return subset[:k, :].copy()

    sel_indices_f, sel_points = best_subset
    # map back to original indices
    sel_orig_indices = orig_idx_map[sel_indices_f]
    subset = points[sel_orig_indices, :].copy()

    # if fewer than k (shouldn't happen), pad from remaining original points
    if subset.shape[0] < k:
        needed = k - subset.shape[0]
        rem_filtered = np.setdiff1d(np.arange(n_f), sel_indices_f, assume_unique=True)
        if rem_filtered.size > 0:
            order = rem_filtered[np.argsort(-single_hvs[rem_filtered])]
            add = points_f[order[:needed], :]
            subset = np.vstack([subset, add])
        else:
            rem_orig = np.setdiff1d(np.arange(n), sel_orig_indices, assume_unique=True)
            if rem_orig.size > 0:
                add = points[rem_orig[:needed], :]
                subset = np.vstack([subset, add])
            else:
                # tile duplicates
                while subset.shape[0] < k:
                    subset = np.vstack([subset, subset[0:1, :]])

    return subset[:k, :].copy()

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D).")
    n, d = points.shape
    if not (isinstance(k, int) and 0 < k <= n):
        raise ValueError("k must be an integer with 0 < k <= number of points")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # Try to import pygmo for hypervolume; if not available, use conservative fallback
    try:
        import pygmo as pg

        def compute_hv_array(arr):
            if arr is None or len(arr) == 0:
                return 0.0
            try:
                return float(pg.hypervolume(np.asarray(arr, dtype=float)).compute(reference_point))
            except Exception:
                # fallback to conservative per-point volumes (max single-point volume)
                diffs = np.maximum(reference_point - np.asarray(arr, dtype=float), 0.0)
                vols = np.prod(diffs, axis=1)
                return float(np.maximum(0.0, vols.max() if vols.size > 0 else 0.0))

        def single_hv_of_point(pt):
            try:
                return float(pg.hypervolume(np.asarray([pt], dtype=float)).compute(reference_point))
            except Exception:
                diffs = np.maximum(reference_point - np.asarray(pt, dtype=float), 0.0)
                return float(np.prod(diffs))

    except Exception:
        # pygmo not available: use deterministic geometric computation (assumes reference_point >= points elementwise)
        def compute_hv_array(arr):
            arr = np.asarray(arr, dtype=float)
            if arr.size == 0:
                return 0.0
            # Conservative (not exact for >1 point with overlap), but acceptable fallback:
            # compute union hypervolume by sampling exact hypervolume via recursive inclusion-exclusion is expensive;
            # instead compute hypervolume via slicing approach only for exactness when d is small; fallback to greedy approximation:
            # We'll compute exact hv for union of axis-aligned boxes using a recursive inclusion-exclusion for modest sizes.
            # If many points, use an upper bound via max single-point volume.
            m = arr.shape[0]
            if m == 0:
                return 0.0
            if m == 1:
                diffs = np.maximum(reference_point - arr[0], 0.0)
                return float(np.prod(diffs))
            # If too many points, use max single point as conservative bound
            if m > 50:
                diffs = np.maximum(reference_point - arr, 0.0)
                vols = np.prod(diffs, axis=1)
                return float(np.maximum(0.0, vols.max() if vols.size > 0 else 0.0))
            # exact union via recursion over dimensions (inclusion by slicing), feasible for moderate m and d
            # sort boxes by one dimension to speed up recursion
            # We'll use a simple recursive algorithm for axis-aligned rectangles' union hypervolume in D dims
            boxes = np.maximum(reference_point - arr, 0.0)  # convert to box sizes (positive or zero)
            # convert each point into interval [ref - size, ref] per dimension
            mins = (reference_point - boxes)
            maxs = np.tile(reference_point, (m,1))
            intervals = list(zip(mins.tolist(), maxs.tolist()))
            # recursive union volume (works for axis-aligned boxes)
            def union_volume(box_list, dim=0):
                if not box_list:
                    return 0.0
                if dim == d:
                    # 0-dim: boxes coincide, return 1
                    return 1.0
                # collect all unique boundaries on this dim
                coords = []
                for (lo, hi) in box_list:
                    coords.append(lo[dim])
                    coords.append(hi[dim])
                coords = sorted(set(coords))
                if len(coords) <= 1:
                    return 0.0
                total = 0.0
                for i in range(len(coords)-1):
                    a = coords[i]
                    b = coords[i+1]
                    if b <= a:
                        continue
                    # select boxes that cover [a,b] on this dim
                    covered = []
                    for (lo, hi) in box_list:
                        if lo[dim] <= a + 1e-15 and hi[dim] >= b - 1e-15:
                            covered.append((lo, hi))
                    if not covered:
                        continue
                    length = b - a
                    # compute union in remaining dims
                    vol_rest = union_volume(covered, dim+1)
                    total += length * vol_rest
                return total
            return float(union_volume(intervals, 0))

        def single_hv_of_point(pt):
            diffs = np.maximum(reference_point - np.asarray(pt, dtype=float), 0.0)
            return float(np.prod(diffs))

    # Precompute single-point hypervolumes
    single_hv = np.zeros(n, dtype=float)
    for i in range(n):
        single_hv[i] = single_hv_of_point(points[i])

    # Determine nondominated (Pareto front) indices assuming minimization (smaller is better)
    # A dominates B if all coords <= and at least one < (within tolerance)
    eps = 1e-12
    dominated = np.zeros(n, dtype=bool)
    for i in range(n):
        if dominated[i]:
            continue
        pi = points[i]
        for j in range(n):
            if i == j or dominated[j]:
                continue
            pj = points[j]
            # check if j dominates i
            if np.all(pj <= pi + eps) and np.any(pj < pi - eps):
                dominated[i] = True
                break
            # check if i dominates j
            if np.all(pi <= pj + eps) and np.any(pi < pj - eps):
                dominated[j] = True
    nondom_indices = [int(i) for i in range(n) if not dominated[i]]
    dominated_indices = [int(i) for i in range(n) if dominated[i]]

    # Candidate pool: nondominated first (likely to contain most valuable points)
    candidates = list(nondom_indices)
    # If fewer nondominated than k, keep dominated ones as fallback sorted by single_hv
    if len(candidates) < k:
        remaining = sorted(dominated_indices, key=lambda i: single_hv[i], reverse=True)
        candidates.extend(remaining)

    # For speed, maintain sets and arrays
    candidate_set = set(candidates)
    selected_indices = []
    selected_set = set()
    current_hv = 0.0
    # Greedy iterative selection: at each step pick candidate with largest exact marginal hv
    for _ in range(min(k, len(candidates))):
        if not candidate_set:
            break
        # Precompute current_hv
        if selected_indices:
            current_hv = compute_hv_array(points[np.array(selected_indices, dtype=int)])
        else:
            current_hv = 0.0

        # Sort remaining candidates by decreasing single_hv (upper bound on marginal)
        rem = sorted(list(candidate_set), key=lambda i: single_hv[i], reverse=True)

        best_idx = None
        best_marginal = 0.0
        # Early stopping: once single_hv(candidate) <= best_marginal, no further candidate can beat best
        for idx in rem:
            ub = single_hv[idx]
            if ub <= best_marginal + 1e-15:
                # further candidates have <= ub (sorted), break
                break
            # If candidate is already dominated by any selected point, skip (adds zero)
            skip = False
            for s in selected_indices:
                if np.all(points[s] <= points[idx] + eps) and np.any(points[s] < points[idx] - eps):
                    skip = True
                    break
            if skip:
                candidate_set.discard(idx)
                continue
            # compute exact marginal
            hv_with = compute_hv_array(np.vstack([points[np.array(selected_indices, dtype=int)], points[idx]]) if selected_indices else np.array([points[idx]]))
            marginal = hv_with - current_hv
            if marginal > best_marginal + 1e-15:
                best_marginal = float(marginal)
                best_idx = int(idx)
        if best_idx is None:
            # no positive marginal found; choose remaining candidate with largest single_hv (heuristic)
            if rem:
                pick = rem[0]
                best_idx = int(pick)
            else:
                break
        # add best_idx
        selected_indices.append(int(best_idx))
        selected_set.add(int(best_idx))
        candidate_set.discard(int(best_idx))
        # remove any candidates now dominated by the new selection (they can never add hv)
        newly_dom = []
        for c in list(candidate_set):
            if np.all(points[best_idx] <= points[c] + eps) and np.any(points[best_idx] < points[c] - eps):
                newly_dom.append(c)
        for c in newly_dom:
            candidate_set.discard(c)

    # If we selected fewer than k (e.g., candidate pool exhausted), fill remaining by global single_hv
    if len(selected_indices) < k:
        remaining = [i for i in range(n) if i not in selected_set]
        remaining_sorted = sorted(remaining, key=lambda i: single_hv[i], reverse=True)
        for idx in remaining_sorted:
            if len(selected_indices) >= k:
                break
            selected_indices.append(int(idx))
            selected_set.add(int(idx))

    # Ensure exactly k selections
    selected_indices = selected_indices[:k]
    subset = points[np.array(selected_indices, dtype=int)]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import time

    try:
        import pygmo as pg
    except Exception:
        pg = None

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, d = points.shape

    if not (isinstance(k, int) and k >= 0):
        raise ValueError("k must be a non-negative integer")
    if k == 0:
        return np.zeros((0, d), dtype=float)
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (d,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # Hypervolume computation with caching; fallback approximate if pygmo not available
    hv_cache = {}

    def hv_of_indices(idx_list):
        # idx_list: iterable of integer indices; treat as sorted tuple key for caching
        if len(idx_list) == 0:
            return 0.0
        key = tuple(sorted(int(i) for i in idx_list))
        if key in hv_cache:
            return hv_cache[key]
        arr = points[np.array(key, dtype=int)]
        if pg is not None:
            try:
                hv_val = float(pg.hypervolume(arr).compute(reference_point))
            except Exception:
                hv_val = 0.0
        else:
            # fallback approximate union: inclusion-exclusion up to pairs (cheap)
            diffs = np.maximum(reference_point - arr, 0.0)
            try:
                if arr.shape[0] == 1:
                    hv_val = float(np.prod(diffs[0]))
                else:
                    singles = np.prod(diffs, axis=1)
                    approx = float(singles.sum())
                    # subtract pairwise overlaps (first-order correction)
                    m = arr.shape[0]
                    if m > 1:
                        for i in range(m):
                            for j in range(i + 1, m):
                                mins = np.minimum(diffs[i], diffs[j])
                                approx -= float(np.prod(mins)) * 0.5
                    hv_val = max(0.0, approx)
            except Exception:
                hv_val = 0.0
        hv_cache[key] = hv_val
        return hv_val

    # Precompute single-point HVs for candidate ranking
    single_hvs = np.zeros(n, dtype=float)
    for i in range(n):
        single_hvs[i] = hv_of_indices([i])

    # Precompute distances (for diversity tie-break), only if not too large
    compute_distances = (n <= 2000)
    if compute_distances:
        diff = points[:, None, :] - points[None, :, :]
        dists = np.sqrt(np.maximum((diff ** 2).sum(axis=2), 0.0))
    else:
        dists = None

    def min_dist_to_set(idx, selected_set):
        if len(selected_set) == 0:
            return np.inf
        if compute_distances:
            return float(np.min(dists[idx, list(selected_set)]))
        else:
            cand = points[idx]
            sel_pts = points[list(selected_set)]
            return float(np.min(np.linalg.norm(sel_pts - cand, axis=1)))

    # Beam search parameters (tunable)
    beam_width = int(min(50, max(8, 6 * k)))  # number of partial solutions to keep
    per_partial_candidates = int(min(n, max(20, 6 * k)))  # top candidates expanded per partial
    time_limit = 5.0  # seconds allowed for the whole search (modest)
    start_time = time.time()

    # Initialize beam with empty partial subset
    # Each entry: (hv_value, frozenset(indices), list(indices_in_order))
    beam = [(0.0, frozenset(), [])]

    # To speed expansions, precompute ranking of points by single_hvs descending
    order_by_single = np.argsort(single_hvs)[::-1]

    for depth in range(1, k + 1):
        new_candidates = []
        # Cap expansions to avoid explosion
        max_expansions = beam_width * per_partial_candidates
        expansions_done = 0

        for hv_val, sel_set, sel_list in beam:
            if (time.time() - start_time) > time_limit:
                break
            # Build list of candidate indices to consider for expansion
            # Choose top unselected by single_hvs (fast)
            cnt = 0
            for idx in order_by_single:
                if idx in sel_set:
                    continue
                cnt += 1
                # Expand by adding idx
                new_sel_list = sel_list + [int(idx)]
                new_hv = hv_of_indices(new_sel_list)
                # Diversity tie-break: prefer sets with larger average min-distance
                # compute diversity score for tie-break only
                if len(new_sel_list) > 0:
                    # compute min distance of newly added point to existing selected (higher is better)
                    if len(sel_set) == 0:
                        min_dist = np.inf
                    else:
                        min_dist = min_dist_to_set(int(idx), sel_set)
                else:
                    min_dist = np.inf
                # store negative min_dist as tie-break (so sorting by hv then min_dist)
                new_candidates.append((new_hv, min_dist, frozenset(new_sel_list), new_sel_list))
                expansions_done += 1
                if expansions_done >= max_expansions:
                    break
                if cnt >= per_partial_candidates:
                    break
            if (time.time() - start_time) > time_limit:
                break

        # if time ran out, break and return the best full-size in beam if any, otherwise best partial
        if (time.time() - start_time) > time_limit:
            break

        if not new_candidates:
            break

        # Keep top beam_width candidates: sort by hv desc then min_dist desc
        # Use partial sort via numpy if large, but here simple sort is fine
        new_candidates.sort(key=lambda x: (x[0], x[1]), reverse=True)
        # Trim to beam_width but also prefer unique sets
        seen = set()
        beam = []
        for hv_val, min_dist, fset, lst in new_candidates:
            if fset in seen:
                continue
            seen.add(fset)
            beam.append((hv_val, fset, lst))
            if len(beam) >= beam_width:
                break

        # Early stopping: if we've constructed full-size subsets at this depth, break loop
        if depth == k:
            break

    # From beam, pick best subset of size k; if none full-size, fill small ones greedily
    best_subset = None
    best_hv = -1.0
    for hv_val, fset, lst in beam:
        if len(lst) == k:
            if hv_val > best_hv:
                best_hv = hv_val
                best_subset = lst
    if best_subset is None:
        # try to complete partials in beam to size k by greedy addition using single_hvs
        for hv_val, fset, lst in beam:
            current_list = list(lst)
            current_set = set(fset)
            current_hv = hv_of_indices(current_list)
            # greedily add remaining points by marginal gain approximated via single_hvs order
            for idx in order_by_single:
                if len(current_list) >= k:
                    break
                if idx in current_set:
                    continue
                # compute marginal gain exactly
                new_hv = hv_of_indices(current_list + [int(idx)])
                # accept if improves current_hv non-negatively, otherwise still accept to fill
                current_list.append(int(idx))
                current_set.add(int(idx))
                current_hv = new_hv
            if len(current_list) == k and current_hv > best_hv:
                best_hv = current_hv
                best_subset = current_list

    # As final fallback, take top-k by single_hvs
    if best_subset is None:
        remaining_sorted = list(order_by_single[:k])
        best_subset = [int(i) for i in remaining_sorted]
        best_hv = hv_of_indices(best_subset)

    # Ensure exactly k elements
    if len(best_subset) > k:
        best_subset = best_subset[:k]
    elif len(best_subset) < k:
        # fill remaining by highest single_hvs not yet chosen
        chosen = set(best_subset)
        for idx in order_by_single:
            if len(best_subset) >= k:
                break
            if int(idx) in chosen:
                continue
            best_subset.append(int(idx))
            chosen.add(int(idx))

    subset = points[np.array(best_subset, dtype=int), :].copy()
    return subset

