            pool_size = min(len(remaining), sample_pool_base)
            # sample candidates: biased by single_hv if available
            if base_probs is None:
                # uniform sample without replacement
                cand_pool = list(rng.choice(remaining, size=pool_size, replace=False))
            else:
                # Build probabilities over remaining
                probs = base_probs[remaining]
                s = probs.sum()
                if s <= 0.0:
                    cand_pool = list(rng.choice(remaining, size=pool_size, replace=False))
                else:
                    probs = probs / s
                    # if pool_size == len(remaining), choose all
                    if pool_size == len(remaining):
                        cand_pool = remaining.copy()
                    else:
                        cand_pool = list(rng.choice(remaining, size=pool_size, replace=False, p=probs))
            # evaluate true marginal hv for candidates in pool
            best_cand = None
            best_gain = 0.0
            for cand in cand_pool:
                hv_new = hv_of_indices(selected + [int(cand)])
                gain = hv_new - current_hv
                if gain > best_gain + tol:
                    best_gain = float(gain)
                    best_cand = int(cand)
            # If none of sampled candidates provide positive gain, optionally try top few remaining deterministically
            if best_cand is None or best_gain <= tol:
                # try top few by single_hv among remaining to avoid missing good points
                top_try = min(10, len(remaining))
                for idx_try in order_by_single:
                    if idx_try in selected_set:
                        continue
                    if idx_try not in remaining:
                        continue
                    hv_new = hv_of_indices(selected + [int(idx_try)])
                    gain = hv_new - current_hv
                    if gain > best_gain + tol:
                        best_gain = float(gain)
                        best_cand = int(idx_try)
                        if best_gain >= 1e-8:
                            break
                # if still no positive gain, break early
                if best_cand is None or best_gain <= tol:
                    break
            # accept best_cand
            selected.append(int(best_cand))
            selected_set.add(int(best_cand))
            current_hv += best_gain

        # If constructed set has fewer than k, fill with highest single_hv remaining
        if len(selected) < k:
            for idx in order_by_single:
                if idx in selected_set:
                    continue
                selected.append(int(idx))
                selected_set.add(int(idx))
                if len(selected) >= k:
                    break
            current_hv = hv_of_indices(selected)

        # record if best
        if current_hv > best_hv + tol:
            best_hv = float(current_hv)
            best_selection = list(selected)

    # As a final polishing step: bounded pairwise swap improvement (outsider candidates are top by single_hv)
    if best_selection is None:
        # fallback: take top-k by single_hv
        best_selection = [int(i) for i in order_by_single[:k]]
        best_hv = hv_of_indices(best_selection)

    selected = list(best_selection[:k])
    selected_set = set(selected)
    current_hv = float(hv_of_indices(selected))

    # Prepare outsider candidates
    outsiders = [i for i in order_by_single if i not in selected_set]
    max_swaps = max(10, 5 * k)
    swaps = 0
    improved = True
    # iterate attempting swaps until no improvement or budget exhausted
    while improved and swaps < max_swaps:
        improved = False
        for si, sel_idx in enumerate(list(selected)):
            # try top outsiders first
            for cand in outsiders[:min(len(outsiders), 50)]:
                if cand in selected_set:
                    continue
                new_sel = list(selected)
                new_sel[si] = int(cand)
                hv_new = hv_of_indices(new_sel)
                if hv_new > current_hv + tol:
                    # apply swap
                    old = selected[si]
                    selected[si] = int(cand)
                    selected_set.remove(int(old))
                    selected_set.add(int(cand))
                    # update outsiders list: remove cand, add old in sorted position by single_hv
                    outsiders = [o for o in outsiders if o != cand]
                    # insert old into outsiders maintaining order_by_single priority (approx)
                    inserted = False
                    for pos, o in enumerate(outsiders):
                        if single_hv[old] > single_hv[o]:
                            outsiders.insert(pos, old)
                            inserted = True
                            break
                    if not inserted:
                        outsiders.append(old)
                    current_hv = float(hv_new)
                    swaps += 1
                    improved = True
                    break
            if improved or swaps >= max_swaps:
                break

    # Final ensure length k
    if len(selected) < k:
        for idx in order_by_single:
            if idx in selected_set:
                continue
            selected.append(int(idx))
            selected_set.add(int(idx))
            if len(selected) >= k:
                break

    subset = points[np.array(selected[:k], dtype=int), :].astype(float, copy=True)
    return subset

